// --- Hyper-Safe USART2 Driver Subsystem ---
void UART2_Init(void)
{
    // 1. Enable Clock for GPIOA and USART2
    RCC_AHB1ENR |= (1 << 0);  // GPIOAEN
    RCC_APB1ENR |= (1 << 17); // USART2EN

    // 2. Configure PA2 as Alternate Function 7 (USART2_TX)
    GPIOA_MODER &= ~(3 << (2 * 2));
    GPIOA_MODER |= (2 << (2 * 2)); // Alternate Function Mode

    GPIOA_AFRL &= ~(0xF << (4 * 2));
    GPIOA_AFRL |= (7 << (4 * 2)); // AF7

    // 3. Configure Baudrate (115200 @ 16MHz internal clock default fallback)
    USART2_BRR = (8 << 4) | 11;

    // 4. Enable USART and Transmitter
    USART2_CR1 |= (1 << 13) | (1 << 3);
}

